@namespace Lumeo
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@if (Label is not null && !InsideFormField)
{
    <label class="block text-sm font-medium mb-1.5">
        @Label
        @if (Required)
        {
            <span class="text-destructive ms-0.5">*</span>
        }
    </label>
}

<div class="@WrapperClass">
    <div class="@($"flex {HeightClass} w-full rounded-md border {(EffectiveInvalid ? "border-destructive" : "border-input")} bg-transparent text-sm overflow-hidden transition-colors {(EffectiveInvalid ? "focus-within:ring-[1.5px] focus-within:ring-destructive/20" : "focus-within:ring-[1.5px] focus-within:ring-ring")}")">
        <input @ref="_inputRef"
               type="@(_showPassword ? "text" : "password")"
               name="@Name"
               id="@FormFieldControlId"
               aria-required="@Required.ToString().ToLowerInvariant()"
               aria-invalid="@EffectiveInvalid.ToString().ToLowerInvariant()"
               aria-describedby="@FormFieldDescribedBy"
               class="flex-1 bg-transparent px-3 py-1 placeholder:text-muted-foreground focus-visible:outline-none disabled:cursor-not-allowed disabled:opacity-50"
               value="@Value"
               placeholder="@(Placeholder ?? L["Password.Placeholder"])"
               disabled="@Disabled"
               @oninput="HandleInput"
               @attributes="AdditionalAttributes" />
        @if (ShowToggle)
        {
            <button type="button"
                    class="flex items-center px-3 text-muted-foreground hover:text-foreground transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-inset"
                    aria-label="@L["Password.Toggle"]"
                    @onclick="ToggleVisibility">
                @if (_showPassword)
                {
                    <Blazicon Svg="Lucide.EyeOff" class="h-4 w-4" />
                }
                else
                {
                    <Blazicon Svg="Lucide.Eye" class="h-4 w-4" />
                }
            </button>
        }
    </div>
    @if (ShowStrength && !string.IsNullOrEmpty(Value))
    {
        <div class="mt-1.5 flex gap-1">
            @for (int i = 0; i < 4; i++)
            {
                var idx = i;
                <div class="@GetStrengthBarClass(idx) h-1 flex-1 rounded-full transition-colors"></div>
            }
        </div>
        <p class="mt-1 text-xs @StrengthLabelClass">@StrengthLabel</p>
    }
</div>

@if (!InsideFormField)
{
    @if (EffectiveInvalid && !string.IsNullOrEmpty(ErrorText))
    {
        <p class="mt-1 text-xs text-destructive" role="alert" aria-live="polite">@ErrorText</p>
    }
    else if (!string.IsNullOrEmpty(HelperText))
    {
        <p class="mt-1 text-xs text-muted-foreground">@HelperText</p>
    }
}

@code {
    [CascadingParameter] private FormField.FormFieldContext? FormField { get; set; }

    [Parameter] public string? Value { get; set; }
    [Parameter] public EventCallback<string?> ValueChanged { get; set; }
    [Parameter] public string? Placeholder { get; set; }
    [Parameter] public bool ShowStrength { get; set; }
    [Parameter] public bool ShowToggle { get; set; } = true;
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public bool Required { get; set; }
    [Parameter] public bool Invalid { get; set; }
    [Parameter] public string? ErrorText { get; set; }
    [Parameter] public string? HelperText { get; set; }
    [Parameter] public string? Label { get; set; }
    [Parameter] public string? Name { get; set; }
    /// <summary>Focuses the underlying password &lt;input&gt; on first render.
    /// See <c>Input.AutoFocus</c> for why the HTML <c>autofocus</c> attribute
    /// doesn't work in Blazor WASM.</summary>
    [Parameter] public bool AutoFocus { get; set; }
    /// <summary>Per-input density override. When null, inherits from any
    /// ancestor <see cref="DensityScope"/>; if neither is set, matches the
    /// historical <c>Comfortable</c> default. Only the field height shifts
    /// between values.</summary>
    [Parameter] public Density? Density { get; set; }
    [CascadingParameter] private Density? InheritedDensity { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool _showPassword;
    private ElementReference _inputRef;

    private Lumeo.Density EffectiveDensity => Density ?? InheritedDensity ?? Lumeo.Density.Comfortable;

    // Height tracks density; Comfortable reproduces the historical h-9.
    private string HeightClass => EffectiveDensity switch
    {
        Lumeo.Density.Compact => "h-8",
        Lumeo.Density.Spacious => "h-10",
        _ => "h-9"
    };

    /// <summary>The underlying password &lt;input&gt; element.</summary>
    public ElementReference Element => _inputRef;

    /// <summary>Programmatically move focus to the input.</summary>
    public ValueTask FocusAsync() => _inputRef.FocusAsync();

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender && AutoFocus)
        {
            try { await _inputRef.FocusAsync(); }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
        }
    }

    private bool EffectiveInvalid => Invalid || FormField?.HasError == true;
    private bool InsideFormField => FormField is not null;

    // Adopt the FormField's generated id + describedby so the field's <label for>
    // resolves to this input and aria-describedby points at the help/error text
    // (Base UI Field a11y). Null outside a FormField — the id/aria attributes are
    // then omitted, and a consumer-set id via AdditionalAttributes still wins
    // (it splats after these). Empty guard avoids id="" if no id was generated.
    private string? FormFieldControlId => string.IsNullOrEmpty(FormField?.ControlId) ? null : FormField!.ControlId;
    private string? FormFieldDescribedBy => FormField?.DescribedBy;

    private string WrapperClass => Cx.Merge("w-full", Class);

    private void ToggleVisibility() => _showPassword = !_showPassword;

    private async Task HandleInput(ChangeEventArgs e)
    {
        Value = e.Value?.ToString();
        await ValueChanged.InvokeAsync(Value);
    }

    private int StrengthScore
    {
        get
        {
            if (string.IsNullOrEmpty(Value)) return 0;
            int score = 0;
            if (Value.Length >= 8) score++;
            if (Value.Any(char.IsUpper)) score++;
            if (Value.Any(char.IsLower)) score++;
            if (Value.Any(char.IsDigit)) score++;
            if (Value.Any(c => !char.IsLetterOrDigit(c))) score++;
            return score;
        }
    }

    private int StrengthLevel => StrengthScore switch
    {
        0 or 1 => 1,
        2 => 2,
        3 => 3,
        _ => 4
    };

    private string StrengthLabel => StrengthLevel switch
    {
        1 => L["Password.Weak"],
        2 => L["Password.Fair"],
        3 => L["Password.Good"],
        4 => L["Password.Strong"],
        _ => ""
    };

    private string StrengthLabelClass => StrengthLevel switch
    {
        1 => "text-destructive",
        2 => "text-warning",
        3 => "text-info",
        4 => "text-success",
        _ => "text-muted-foreground"
    };

    private string GetStrengthBarClass(int index) =>
        index < StrengthLevel
            ? StrengthLevel switch
            {
                1 => "bg-destructive",
                2 => "bg-warning",
                3 => "bg-info",
                4 => "bg-success",
                _ => "bg-muted"
            }
            : "bg-muted";
}
